// === Preparar Arquivos (Run Once for Each Item) ===
// Processa UM clip por execucao -> nunca estoura o limite de 300s do task runner.
// Versao paste-safe: sem sequencias \n em strings (usa NL = fromCharCode(10)).
const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');
const TMP = '/tmp';
const NL = String.fromCharCode(10);

function resolverCaminho(bin) {
  if (!bin) return null;
  const id = bin.id ? String(bin.id).split(':').pop() : null;
  const candidatos = [];
  if (id) {
    candidatos.push(
      path.join('/home/node/.n8n/binaryData', id),
      path.join('/home/node/.n8n/binaryData', id + '.bin'),
      path.join('/data/.n8n/binaryData', id),
      path.join('/tmp', id)
    );
  }
  for (const c of candidatos) { try { if (fs.existsSync(c)) return c; } catch (e) {} }
  return null;
}

async function getBuf(prop, bin) {
  try {
    const b = await this.helpers.getBinaryDataBuffer(0, prop);
    if (b && b.length) return b;
  } catch (e) {}
  const p = resolverCaminho(bin && bin[prop]);
  if (p) { try { return fs.readFileSync(p); } catch (e) {} }
  return null;
}

function escapeDraw(t) {
  return String(t || '')
    .split('\\').join('\\\\')
    .split(':').join('\\:')
    .split("'").join(String.fromCharCode(8217))
    .split('%').join('\\%')
    .split(',').join('\\,');
}
function wrapTexto(t, maxChars) {
  const palavras = String(t || '').split(/\s+/);
  const linhas = [];
  let atual = '';
  for (const p of palavras) {
    if ((atual + ' ' + p).trim().length > maxChars) {
      if (atual) linhas.push(atual.trim());
      atual = p;
    } else { atual = (atual + ' ' + p).trim(); }
  }
  if (atual) linhas.push(atual.trim());
  return linhas.join(NL);
}
function escapeAss(t) {
  return String(t == null ? '' : t)
    .split('\\').join(' ')
    .split('{').join('(')
    .split('}').join(')')
    .replace(/\s+/g, ' ')
    .trim();
}
function assTime(t) {
  if (!(t > 0)) t = 0;
  let cs = Math.round(t * 100);
  const h = Math.floor(cs / 360000); cs -= h * 360000;
  const m = Math.floor(cs / 6000); cs -= m * 6000;
  const s = Math.floor(cs / 100); cs -= s * 100;
  const pad = (n, l) => String(n).padStart(l, '0');
  return h + ':' + pad(m, 2) + ':' + pad(s, 2) + '.' + pad(cs, 2);
}

const FONT = (function () {
  const fontes = [
    '/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/dejavu/DejaVuSans-Bold.ttf',
    '/usr/share/fonts/truetype/liberation/LiberationSans-Bold.ttf'
  ];
  for (const f of fontes) { try { if (fs.existsSync(f)) return f; } catch (e) {} }
  return null;
})();
const FONTS_DIR = FONT ? path.dirname(FONT) : '';
const ASS_FONT = (FONT && /liberation/i.test(FONT)) ? 'Liberation Sans' : 'DejaVu Sans';

const json = $input.item.json || {};
const bin = $input.item.binary || {};
const clipNum = json.clip || (($itemIndex || 0) + 1);

const audioBuf = await getBuf.call(this, 'data', bin);
const imgBuf = await getBuf.call(this, 'foto', bin);
if (!audioBuf || !imgBuf) {
  return { json: { clip: clipNum, skipped: true, texto_narracao: json.texto_narracao || '', articleTitle: json.articleTitle || '' } };
}

const audioPath = TMP + '/audio_' + clipNum + '.mp3';
const wavPath = TMP + '/audio_' + clipNum + '.wav';
const webpPath = TMP + '/img_' + clipNum + '.webp';
const pngPath = TMP + '/img_' + clipNum + '.png';
const outPath = TMP + '/clip_' + clipNum + '.mp4';
const assPath = TMP + '/cap_' + clipNum + '.ass';

fs.writeFileSync(audioPath, audioBuf);
fs.writeFileSync(webpPath, imgBuf);

execSync('ffmpeg -y -i "' + audioPath + '" -ar 44100 -ac 2 "' + wavPath + '"', { stdio: 'ignore', timeout: 120000 });
execSync('ffmpeg -y -i "' + webpPath + '" -vf "scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920" "' + pngPath + '"', { stdio: 'ignore', timeout: 120000 });

let dur = parseFloat(json.duration) || 4;
try {
  const probe = execSync('ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 "' + wavPath + '"', { timeout: 60000 }).toString().trim();
  const d = parseFloat(probe);
  if (!isNaN(d) && d > 0) dur = d;
} catch (e) {}
const duracaoSeg = dur;

const fps = 25;
const frames = Math.ceil(dur * fps);

const zoomIn = (clipNum % 2 === 1);
const zoomExpr = zoomIn ? "min(zoom+0.0012,1.3)" : "if(lte(zoom,1.0),1.3,max(1.0,zoom-0.0012))";
const zoomPart = "zoompan=z='" + zoomExpr + "':d=" + frames + ":s=1080x1920:fps=" + fps;

const narr = String(json.texto_narracao || '').trim();
const words = narr.split(/\s+/).filter(Boolean);
const wordCount = words.length;

let assOk = false;
if (FONT && wordCount > 0) {
  try {
    const slice = duracaoSeg / wordCount;
    const groupSize = 2;
    const dialogues = [];
    const BS = String.fromCharCode(92);
    const tags = '{' + BS + 'fad(60,40)' + BS + 'fscx55' + BS + 'fscy55' + BS + 't(0,120,' + BS + 'fscx100' + BS + 'fscy100)}';
    for (let w = 0; w < wordCount; w += groupSize) {
      const grp = words.slice(w, w + groupSize);
      const startT = w * slice;
      const endIdx = Math.min(w + groupSize, wordCount);
      let endT = endIdx * slice;
      if (endIdx >= wordCount) endT = duracaoSeg;
      const txt = escapeAss(grp.join(' ').toLocaleUpperCase('pt-BR'));
      if (!txt) continue;
      dialogues.push('Dialogue: 0,' + assTime(startT) + ',' + assTime(endT) + ',Cap,,0,0,0,,' + tags + txt);
    }
    const head = [
      '[Script Info]',
      'ScriptType: v4.00+',
      'PlayResX: 1080',
      'PlayResY: 1920',
      'WrapStyle: 2',
      'ScaledBorderAndShadow: yes',
      '',
      '[V4+ Styles]',
      'Format: Name, Fontname, Fontsize, PrimaryColour, SecondaryColour, OutlineColour, BackColour, Bold, Italic, Underline, StrikeOut, ScaleX, ScaleY, Spacing, Angle, BorderStyle, Outline, Shadow, Alignment, MarginL, MarginR, MarginV, Encoding',
      'Style: Cap,' + ASS_FONT + ',90,&H00FFFFFF,&H000000FF,&H00000000,&H64000000,-1,0,0,0,100,100,0,0,1,6,3,2,80,80,430,1',
      '',
      '[Events]',
      'Format: Layer, Start, End, Style, MarginL, MarginR, MarginV, Effect, Text'
    ];
    const assContent = head.join(NL) + NL + dialogues.join(NL) + NL;
    fs.writeFileSync(assPath, assContent, { encoding: 'utf8' });
    assOk = fs.existsSync(assPath) && fs.statSync(assPath).size > 0;
  } catch (e) { assOk = false; }
}

const renderFFmpeg = function (vfStr) {
  execSync('ffmpeg -y -loop 1 -i "' + pngPath + '" -i "' + wavPath + '" -t ' + dur.toFixed(3) + ' -r ' + fps + ' -vf "' + vfStr + '" -c:v libx264 -preset veryfast -pix_fmt yuv420p -c:a aac -b:a 192k -shortest -movflags +faststart "' + outPath + '"', { stdio: 'ignore', timeout: 240000 });
};

let rendered = false;
if (assOk) {
  try {
    const escAss = assPath.split('\\').join('\\\\').split(':').join('\\:').split("'").join("\\'");
    const escDir = FONTS_DIR.split('\\').join('\\\\').split(':').join('\\:').split("'").join("\\'");
    const dirOpt = FONTS_DIR ? ":fontsdir='" + escDir + "'" : '';
    const vf = zoomPart + ",format=yuv420p,ass='" + escAss + "'" + dirOpt;
    renderFFmpeg(vf);
    rendered = fs.existsSync(outPath) && fs.statSync(outPath).size > 0;
  } catch (e) { rendered = false; }
}

if (!rendered) {
  const texto = escapeDraw(wrapTexto(json.texto_narracao, 26));
  const fontPart = FONT ? "fontfile='" + FONT + "':" : '';
  const drawtext = "drawtext=" + fontPart + "text='" + texto + "':fontcolor=white:fontsize=56:line_spacing=10:box=1:boxcolor=black@0.55:boxborderw=22:borderw=4:bordercolor=black:x=(w-text_w)/2:y=h-h*0.28";
  const vf = zoomPart + "," + drawtext;
  renderFFmpeg(vf);
}

const outBuf = fs.readFileSync(outPath);
return {
  json: { clip: clipNum, texto_narracao: json.texto_narracao || '', duration: dur, articleTitle: json.articleTitle || '' },
  binary: { data: await this.helpers.prepareBinaryData(outBuf, 'clip_' + clipNum + '.mp4', 'video/mp4') }
};
